// ================================================
// MERGE ALL SHEETS → ONE ROW PER PATIENT PER DAY
// ================================================

const bpRows       = $('Read: Blood Pressure Readings').all().map(i => i.json);
const glucoseRows  = $('Read: Glucose Readings').all().map(i => i.json);
const activityRows = $('Read: Activity & Sleep Data').all().map(i => i.json);
const patientRows  = $('Read: Patient Master List').all().map(i => i.json);

// Index patients by ID
const patientMap = {};
for (const p of patientRows) {
  patientMap[p.PatientID] = p;
}

// Collect all unique patient IDs seen today
const allIDs = new Set([
  ...bpRows.map(r => r.PatientID),
  ...glucoseRows.map(r => r.PatientID),
  ...activityRows.map(r => r.PatientID)
]);

const results = [];

for (const pid of allIDs) {
  const patient = patientMap[pid] || {};

  const bpList = bpRows.filter(r => r.PatientID === pid);
  const bp     = bpList.length > 0 ? bpList[bpList.length - 1] : {};

  const glList = glucoseRows.filter(r => r.PatientID === pid);
  const gl     = glList.length > 0 ? glList[glList.length - 1] : {};

  const acList = activityRows.filter(r => r.PatientID === pid);
  const ac     = acList.length > 0 ? acList[acList.length - 1] : {};

  results.push({
    json: {
      patientId:   pid,
      patientName: patient.PatientName || bp.PatientName || gl.PatientName || 'Unknown',
      patientEmail: patient.PatientEmail || '',
      doctorEmail:  patient.DoctorEmail  || 'user@example.com',
      condition:    patient.Condition    || '',
      date:         new Date().toISOString().split('T')[0],
      targets: {
        systolic:        parseInt(patient.TargetBP_Sys)         || 130,
        diastolic:       parseInt(patient.TargetBP_Dia)         || 80,
        glucoseFasting:  parseInt(patient.TargetGlucose_Fasting)|| 126,
        steps:           parseInt(patient.TargetSteps)          || 7000
      },
      vitals: {
        bloodPressure: {
          systolic:  bp.Systolic  ? parseInt(bp.Systolic)  : null,
          diastolic: bp.Diastolic ? parseInt(bp.Diastolic) : null,
          pulse:     bp.Pulse     ? parseInt(bp.Pulse)     : null,
          time:      bp.Time || null
        },
        glucose: {
          level:    gl.GlucoseLevel ? parseFloat(gl.GlucoseLevel) : null,
          mealType: gl.MealType     || 'unknown',
          insulin:  gl.InsulinTaken || 'No'
        }
      },
      activity: {
        steps:         ac.Steps          ? parseInt(ac.Steps)          : null,
        activeMinutes: ac.ActiveMinutes  ? parseInt(ac.ActiveMinutes)  : null,
        calories:      ac.CaloriesBurned ? parseInt(ac.CaloriesBurned) : null,
        weight:        ac.Weight_kg      ? parseFloat(ac.Weight_kg)    : null
      },
      sleep: {
        hours:   ac.SleepHours   ? parseFloat(ac.SleepHours) : null,
        quality: ac.SleepQuality || null
      },
      dataCompleteness: {
        hasBP:       bp.Systolic     != null,
        hasGlucose:  gl.GlucoseLevel != null,
        hasActivity: ac.Steps        != null,
        hasSleep:    ac.SleepHours   != null
      }
    }
  });
}

return results;

// ================================================
// AI RISK SCORING ENGINE
// AHA + ADA clinical guidelines
// ================================================

const d = $input.item.json;
const { vitals, activity, sleep, targets } = d;

const anomalies = [];
let riskPoints  = 0;
let maxRisk     = 0;

if (vitals.bloodPressure.systolic !== null) {
  const sys = vitals.bloodPressure.systolic;
  const dia = vitals.bloodPressure.diastolic;
  maxRisk += 30;

  if (sys >= 180 || dia >= 120) {
    anomalies.push({ severity:'critical', category:'blood_pressure',
      message:`Hypertensive Crisis: ${sys}/${dia} mmHg – IMMEDIATE ACTION` });
    riskPoints += 30;
  } else if (sys >= 140 || dia >= 90) {
    anomalies.push({ severity:'high', category:'blood_pressure',
      message:`Stage 2 Hypertension: ${sys}/${dia} mmHg` });
    riskPoints += 20;
  } else if (sys >= 130 || dia >= 80) {
    anomalies.push({ severity:'medium', category:'blood_pressure',
      message:`Stage 1 Hypertension: ${sys}/${dia} mmHg` });
    riskPoints += 10;
  } else if (sys < 90 || dia < 60) {
    anomalies.push({ severity:'high', category:'blood_pressure',
      message:`Hypotension: ${sys}/${dia} mmHg` });
    riskPoints += 15;
  }
}

if (vitals.glucose.level !== null) {
  const g  = vitals.glucose.level;
  const ft = vitals.glucose.mealType.toLowerCase().includes('fast');
  maxRisk += 30;

  if (g < 70) {
    anomalies.push({ severity:'critical', category:'glucose',
      message:`HYPOGLYCEMIA: ${g} mg/dL – URGENT` });
    riskPoints += 30;
  } else if (g >= (ft ? 180 : 250)) {
    anomalies.push({ severity:'critical', category:'glucose',
      message:`Severe Hyperglycemia: ${g} mg/dL (${vitals.glucose.mealType})` });
    riskPoints += 30;
  } else if (g >= (ft ? 126 : 200)) {
    anomalies.push({ severity:'high', category:'glucose',
      message:`Hyperglycemia: ${g} mg/dL (${vitals.glucose.mealType})` });
    riskPoints += 20;
  } else if (g >= (ft ? 100 : 140)) {
    anomalies.push({ severity:'medium', category:'glucose',
      message:`Pre-diabetic range: ${g} mg/dL (${vitals.glucose.mealType})` });
    riskPoints += 10;
  }
}

if (activity.steps !== null) {
  maxRisk += 10;
  if (activity.steps < 2000) {
    anomalies.push({ severity:'medium', category:'activity',
      message:`Very low activity: ${activity.steps} steps (target: ${targets.steps})` });
    riskPoints += 7;
  } else if (activity.steps < 4000) {
    anomalies.push({ severity:'low', category:'activity',
      message:`Below activity target: ${activity.steps} steps` });
    riskPoints += 3;
  }
}

if (sleep.hours !== null) {
  maxRisk += 10;
  if (sleep.hours < 5) {
    anomalies.push({ severity:'medium', category:'sleep',
      message:`Insufficient sleep: ${sleep.hours}h (target: 7-9h)` });
    riskPoints += 8;
  } else if (sleep.hours < 6) {
    anomalies.push({ severity:'low', category:'sleep',
      message:`Low sleep: ${sleep.hours}h` });
    riskPoints += 4;
  }
  if (sleep.quality === 'Very Poor') {
    anomalies.push({ severity:'medium', category:'sleep',
      message:`Very poor sleep quality reported` });
    riskPoints += 4;
  }
}

const riskScore = maxRisk > 0 ? Math.min(100, Math.round((riskPoints / maxRisk) * 100)) : 0;
const hasCritical = anomalies.some(a => a.severity === 'critical');
const hasHigh     = anomalies.some(a => a.severity === 'high');

let riskLevel, escalate;
if (hasCritical || riskScore >= 70) { riskLevel = 'CRITICAL'; escalate = true; }
else if (hasHigh || riskScore >= 40) { riskLevel = 'HIGH';     escalate = true; }
else if (riskScore >= 20)            { riskLevel = 'MEDIUM';   escalate = false; }
else                                  { riskLevel = 'LOW';      escalate = false; }

return [{ json: {
  ...d,
  analysis: {
    riskScore, riskLevel, escalate,
    anomalies,
    totalAnomalies: anomalies.length,
    criticalCount:  anomalies.filter(a => a.severity === 'critical').length,
    timestamp: new Date().toISOString()
  }
}}];

// ================================================
// CLINICAL INTERVENTION RECOMMENDATIONS
// ================================================

const d = $input.item.json;
const { analysis, vitals, activity, sleep } = d;
const recs = [];

const bp  = vitals.bloodPressure;
const glu = vitals.glucose;

if (bp.systolic >= 180) {
  recs.push({ priority:1, action:'IMMEDIATE',
    rec:'Emergency evaluation. Hypertensive crisis protocol. Check for headache, chest pain, or vision changes. Consider IV antihypertensive.',
    followUp:'2 hours' });
} else if (bp.systolic >= 140) {
  recs.push({ priority:2, action:'REVIEW MEDICATION',
    rec:'Review antihypertensive adherence and dosing. Consider adjusting ACE inhibitor/ARB. Home BP monitoring twice daily.',
    followUp:'24 hours' });
  recs.push({ priority:4, action:'LIFESTYLE',
    rec:'DASH diet counselling. Sodium restriction <2,300mg/day. 30 min aerobic activity 5x/week.',
    followUp:'1 week' });
} else if (bp.systolic >= 130) {
  recs.push({ priority:3, action:'MONITOR',
    rec:'Stage 1 hypertension. Reinforce lifestyle changes. Reassess in 1 month.',
    followUp:'1 month' });
}

if (bp.systolic !== null && bp.systolic < 90) {
  recs.push({ priority:1, action:'IMMEDIATE',
    rec:'Hypotension detected. Check for dehydration, medication side effects, or orthostatic hypotension. Increase fluid intake.',
    followUp:'4 hours' });
}

if (glu.level !== null) {
  const g = glu.level;
  if (g < 70) {
    recs.push({ priority:1, action:'IMMEDIATE',
      rec:'Hypoglycaemia protocol: 15-20g fast-acting carbs now (juice/glucose tablets). Recheck in 15 min. Review insulin dosing.',
      followUp:'15 minutes' });
  } else if (g > 250) {
    recs.push({ priority:2, action:'CONTACT PATIENT',
      rec:'Severe hyperglycaemia. Check ketones if T1D. Review medication adherence. Assess for illness/stress trigger.',
      followUp:'4 hours' });
  } else if (g > 180) {
    recs.push({ priority:3, action:'REVIEW MEDICATION',
      rec:'Uncontrolled hyperglycaemia. Review current diabetes medication. Consider dose adjustment or adding GLP-1 agonist.',
      followUp:'48 hours' });
  }
}

if (activity.steps !== null && activity.steps < 2000) {
  recs.push({ priority:4, action:'LIFESTYLE',
    rec:'Severe sedentary behaviour. Prescribe structured 20-min daily walks. Consider physiotherapy referral.',
    followUp:'1 week' });
}

if (sleep.hours !== null && sleep.hours < 5) {
  recs.push({ priority:4, action:'LIFESTYLE',
    rec:'Severe sleep deprivation worsens BP and glucose control. Screen for sleep apnoea. CBT-I or sleep hygiene programme.',
    followUp:'2 weeks' });
}

recs.sort((a,b) => a.priority - b.priority);

return [{ json: {
  ...d,
  interventions: {
    recommendations: recs,
    totalRecs: recs.length,
    immediateActions: recs.filter(r => r.action === 'IMMEDIATE').length,
    generatedAt: new Date().toISOString()
  }
}}];

